+    #[test]
+    fn privacy_accountant_exhaustion() {
+        let mut acc = PrivacyAccountant::new(1.0, 1e-5);
+        // Use a very small sigma to burn budget fast
+        for _ in 0..100 {
+            acc.record_gaussian(0.1, 10.0, 1e-5, 10);
+        }
